import React, { useEffect, useState } from 'react'
import { Login } from './components/Login';
import { Register } from './components/Register';

export const IndexPage = () => {
    const [pageshow,setPageshow] = useState("login");
    const [menu,setMenu] = useState({status:false,page:"none"});

    useEffect(()=>{
        document.title = pageshow === "login" ? 'Login' : 'Register';
    },[pageshow])

    return (
        <div className='IndexPage w-screen h-screen bg-repeat-x' 
        style={{
            backgroundImage:"url('./requiredfiles/wave.png')",
            backgroundPosition: "center bottom"
        }}>
            <div className="flex">
                <div className='pt-[10px] w-[80%] lg:w-[50%] flex items-center'>
                    <img className="ml-[20px] sm:ml-[80px] w-[50px] sm:w-[80px]" src="./requiredfiles/Logo.png" alt="" />
                    <h1 className='ml-[10px] pt-[10px] text-[35px] sm:text-[40px] font-[Sevillana]'>Secure Notes</h1>
                </div>
                <div className='desktop items-center justify-end w-[50%] hidden lg:block'>
                    {pageshow==="login" ? (
                        <div className='pt-[30px] w-[100%] flex items-center justify-end'>
                            <div className="mr-[30px] cursor-pointer" onClick={()=>{setPageshow("register")}}>
                                <h1 className='text-[20px] font-[Barlow]'>Registers</h1>
                            </div>                    
                            <div className="mr-[60px] cursor-pointer py-[5px] px-[15px] bg-[#845EC2] text-white rounded-md " style={{boxShadow:"1px 1px 30px 1px #845EC2"}} onClick={()=>{setPageshow("login")}}>
                                <h1 className='text-[20px] font-[Barlow]'>Login</h1>
                            </div>
                        </div>
                    ): (
                        <div className='pt-[30px] w-[100%] flex items-center justify-end'>
                            <div className="mr-[30px] cursor-pointer py-[5px] px-[15px] bg-[#845EC2] text-white rounded-md " style={{boxShadow:"1px 1px 30px 1px #845EC2"}} onClick={()=>{setPageshow("register")}}>
                                <h1 className='text-[20px] font-[Barlow]'>Registers</h1>
                            </div>                    
                            <div className="mr-[80px] cursor-pointer" onClick={()=>{setPageshow("login")}}>
                                <h1 className='text-[20px] font-[Barlow]'>Login</h1>
                            </div>
                        </div>
                    )}
                </div>

                <div className='mobile items-center justify-end w-[20%] block lg:hidden'>
                    {pageshow==="login" ? (
                        <div className='pt-[30px] sm:pt-[40px] w-[100%] flex items-center justify-end'>
                            {menu.status ? (
                                <i className="fa-solid fa-caret-up pr-[20px] sm:pr-[60px] text-[30px]" onClick={()=>{ setMenu({status:false,page:"none"})}}></i>
                            ):(
                                <i className="fa-solid fa-bars pr-[20px] sm:pr-[60px] text-[30px]" onClick={()=>{ setMenu({status:true,page:"login"})}}></i>
                            )}                           
                        </div>
                    ): (
                        <div className='pt-[30px] sm:pt-[40px] w-[100%] flex items-center justify-end'>
                            {menu.status ? (
                                <i className="fa-solid fa-caret-up pr-[20px] sm:pr-[60px] text-[30px]" onClick={()=>{ setMenu({status:false,page:"none"})}}></i>
                            ):(
                                <i className="fa-solid fa-bars pr-[20px] sm:pr-[60px] text-[30px]" onClick={()=>{ setMenu({status:true,page:"register"})}}></i>
                            )}
                        </div>
                    )}
                </div>   

                {menu.status && menu.page === "login" ? (
                    <div className="block lg:hidden absolute top-0 right-0 z-10 mt-[65px] mr-[30px] w-72 list-none flex-col rounded bg-[#B0A8B9] py-2 shadow-md shadow-slate-500/10">
                        Login
                    </div>
                ):null}  

                {menu.status && menu.page === "register" ? (
                    <div>
                        register
                    </div>
                ):null}           

            </div>
            
            <div className='page mt-[50px] flex justify-center'>
                {pageshow==="login" ? <Login/> : <Register/>}  
            </div>         
            
        </div>
    )
}
